#include <bits/stdc++.h>
using namespace std;

bool cmp(int a, int b) {
    return a > b;
}

int main() {
    int n, a[55];
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }
    sort(a, a + n, cmp);
    for (int cnt = 1; ; cnt++) {
        int day = a[0] * cnt;
        bool flag = true;
        for (int i = 1; i < n; i++) {
            if (day % a[i] > 0) {
                flag = false;
                break;
            }
        }
        if (flag) {
            cout << day;
            return 0;
        }
    }
    return 0;
}
